+// Package treemap implements an ordered map backed by parallel sorted slices.
+package treemap
+
+import "sort"
+
+// Map is an ordered map from string keys to string values backed by
+// parallel slices kept in sorted key order.
+type Map struct {
+	keys []string
+	vals []string
+}
+
+// New returns an empty Map.
+func New() *Map {
+	return &Map{}
+}
+
+// Len returns the number of entries in the map.
+func (m *Map) Len() int {
+	return len(m.keys)
+}
+
+// search returns the index where key is or should be inserted.
+func (m *Map) search(key string) int {
+	return sort.Search(len(m.keys), func(i int) bool {
+		return m.keys[i] >= key
+	})
+}
+
+// Get returns the value associated with key.
+func (m *Map) Get(key string) (string, bool) {
+	i := m.search(key)
+	if i < len(m.keys) && m.keys[i] == key {
+		return m.vals[i], true
+	}
+	return "", false
+}
+
+// Set inserts or updates the value for key.
+func (m *Map) Set(key, val string) {
+	i := m.search(key)
+	if i < len(m.keys) && m.keys[i] == key {
+		m.vals[i] = val
+		return
+	}
+	// Grow both backing slices by one and open a gap at index i by
+	// shifting the existing entries from i onward one slot to the right.
+	m.keys = append(m.keys, "")
+	m.vals = append(m.vals, "")
+	copy(m.keys[i+1:], m.keys[i:])
+	copy(m.vals[i+1:], m.vals[i:])
+	m.keys[i] = key
+	m.vals[i] = val
+}
+
+// Keys returns the keys in sorted order.
+func (m *Map) Keys() []string {
+	out := make([]string, len(m.keys))
+	copy(out, m.keys)
+	return out
+}
