@@
+package treemap
+
+import "testing"
+
+func TestSetInsertOutOfOrder(t *testing.T) {
+	m := New()
+	for _, k := range []string{"d", "b", "f", "a", "c", "e"} {
+		m.Set(k, k+"v")
+	}
+	if m.Len() != 6 {
+		t.Fatalf("len=%d want 6", m.Len())
+	}
+	for _, k := range []string{"a", "b", "c", "d", "e", "f"} {
+		v, ok := m.Get(k)
+		if !ok || v != k+"v" {
+			t.Fatalf("Get(%q) = %q,%v", k, v, ok)
+		}
+	}
+	want := []string{"a", "b", "c", "d", "e", "f"}
+	got := m.Keys()
+	for i := range want {
+		if got[i] != want[i] {
+			t.Fatalf("keys[%d]=%q want %q", i, got[i], want[i])
+		}
+	}
+}
+
+func TestSetFrontMiddleEnd(t *testing.T) {
+	m := New()
+	m.Set("m", "1")
+	m.Set("z", "2") // end
+	m.Set("a", "3") // front
+	m.Set("p", "4") // middle
+	if m.Len() != 4 {
+		t.Fatalf("len=%d want 4", m.Len())
+	}
+	for k, w := range map[string]string{"a": "3", "m": "1", "p": "4", "z": "2"} {
+		if v, ok := m.Get(k); !ok || v != w {
+			t.Fatalf("Get(%q)=%q,%v want %q", k, v, ok, w)
+		}
+	}
+}
+
+func TestSetOverwrite(t *testing.T) {
+	m := New()
+	m.Set("a", "1")
+	m.Set("a", "2")
+	if m.Len() != 1 {
+		t.Fatalf("len=%d want 1", m.Len())
+	}
+	if v, _ := m.Get("a"); v != "2" {
+		t.Fatalf("v=%q want 2", v)
+	}
+}
